	 --  and t.no_poliza not in ('1110818','1025584','1020928','1071982')

	{select distinct t.no_poliza,
		   t.no_endoso
	  into _no_poliza,
		   _no_endoso
	  from emifacon_transf t, emipomae e
	 where e.no_poliza = t.no_poliza
	   and e.vigencia_inic >= '01/01/2018'}

	{begin
		on exception in(-535)

		end exception 	
		begin work;
	end}

	select sum(prima)
	  into _prima_rea
	  from emifacon r, reacomae c
	 where r.cod_contrato = c.cod_contrato
	   and r.no_poliza = _no_poliza
	   and r.no_endoso = _no_endoso
	   and c.tipo_contrato = 1;

	update endedmae
	   set prima_retenida = _prima_rea
	 where no_poliza = _no_poliza
	   and no_endoso = _no_endoso;

	update endedhis
	   set prima_retenida = _prima_rea
	 where no_poliza = _no_poliza
	   and no_endoso = _no_endoso;
end foreach

return 0,'Actualización Exitosa';
